func newNovelTripCmd(flags *rootFlags) *cobra.Command {
	var radius int
	cmd := &cobra.Command{
		Use:   "trip <place-or-lat,lng> [more stops...]",
		Short: "Collect quirky stops near a list of cities or coordinates in one call, deduped and labeled by stop.",
		Long: strings.Trim(`
Collect offbeat attractions near each stop on a route in one call. Each stop is a
place name (geocoded) or lat,lng. Results within --radius miles are gathered,
deduplicated across stops (each attraction appears once, under its first stop),
and labeled by stop. A failed stop is reported in fetch_failures without aborting
the rest.`, "\n"),
		Example: strings.Trim(`
  roadside-america-pp-cli trip "Austin, TX" "Waco, TX" --radius 15
  roadside-america-pp-cli trip "Austin, TX" "Waco, TX" "Dallas, TX" --radius 15 --json`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 && cmd.Flags().NFlag() == 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), "would collect attractions near each trip stop")
				return nil
			}
			if cliutil.IsVerifyEnv() {
				// Hermetic: skip live geocoding (Nominatim) under verify.
				return flags.printJSON(cmd, tripView{Source: roadside.SourceLabel, Stops: []tripStop{}})
			}
			if len(args) == 0 {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("at least one stop (place name or lat,lng) is required"))
			}
			if flags.dataSource == "local" {
				return usageErr(fmt.Errorf("trip requires live data (coordinates are not cached); use 'state <ST>' for offline browsing"))
			}
			if radius <= 0 {
				radius = 15
			}

			ctx := cmd.Context()
			s, err := openRoadsideStore(ctx)
			if err != nil {
				return err
			}
			defer s.Close()
			c, err := flags.newClient()
			if err != nil {
				return err
			}

			stops := args
			note := ""
			if max := dogfoodScanCap(len(stops)); max < len(stops) {
				stops = stops[:max]
				note = "limited to the first stop under live-dogfood timeouts"
			}

			seen := map[string]bool{}
			view := tripView{Source: roadside.SourceLabel, RadiusMi: radius, Stops: make([]tripStop, 0, len(stops)), Note: note}
			for _, stop := range stops {
				ts := tripStop{Stop: stop, Attractions: []roadside.Attraction{}}
				lat, lng, label, gerr := resolveLocation(ctx, s, stop, flags.timeout)
				if gerr != nil {
					ts.Error = fmt.Sprintf("could not resolve %q: %v", stop, gerr)
					view.FetchFailures = append(view.FetchFailures, ts.Error)
					view.Stops = append(view.Stops, ts)
					continue
				}
				ts.Label, ts.Lat, ts.Lng = label, lat, lng
				atts, ferr := fetchNearbyAttractions(ctx, c, lat, lng, roadside.MilesToDelta(float64(radius)))
				if ferr != nil {
					// A throttle stops the whole trip rather than silently
					// skipping stops; other failures are recorded per-stop.
					var rl *cliutil.RateLimitError
					var ae *client.APIError
					if errors.As(ferr, &rl) || (errors.As(ferr, &ae) && ae.StatusCode == 429) {
						return classifyFetchErr(ferr)
					}
					ts.Error = fmt.Sprintf("fetch failed near %q: %v", stop, ferr)
					view.FetchFailures = append(view.FetchFailures, ts.Error)
					view.Stops = append(view.Stops, ts)
					continue
				}
				cacheAttractions(s, atts)
				for _, a := range atts {
					if a.DistanceMi > 0 && a.DistanceMi > float64(radius) {
						continue
					}
					if seen[a.ID] {
						continue
					}
					seen[a.ID] = true
					ts.Attractions = append(ts.Attractions, a)
				}
				ts.Count = len(ts.Attractions)
				view.Stops = append(view.Stops, ts)
			}
			view.UniqueCount = len(seen)

			if len(view.FetchFailures) > 0 {
				fmt.Fprintf(cmd.ErrOrStderr(), "warning: %d of %d stops failed; unique_count covers the successful stops\n", len(view.FetchFailures), len(stops))
			}

			if machineOutput(cmd, flags) {
				return flags.printJSON(cmd, view)
			}
			w := cmd.OutOrStdout()
			for _, ts := range view.Stops {
				header := ts.Stop
				if ts.Label != "" && ts.Label != ts.Stop {
					header = fmt.Sprintf("%s (%s)", ts.Stop, ts.Label)
				}
				fmt.Fprintf(w, "%s\n", bold(header))
				if ts.Error != "" {
					fmt.Fprintf(w, "  %s\n\n", ts.Error)
					continue
				}
				tw := newTabWriter(w)
				for _, a := range ts.Attractions {
					loc := a.City
					if a.State != "" {
						loc = strings.TrimPrefix(loc+", "+a.State, ", ")
					}
					fmt.Fprintf(tw, "  %s\t%s\t%s\n", truncate(a.Name, 44), loc, a.Distance)
				}
				tw.Flush()
				fmt.Fprintf(w, "  (%d within %d mi)\n\n", ts.Count, radius)
			}
			fmt.Fprintf(w, "%d unique attractions across %d stop(s) — %s\n", view.UniqueCount, len(view.Stops), roadside.SourceLabel)
			return nil
		},
	}
	cmd.Flags().IntVar(&radius, "radius", 15, "Search radius in miles around each stop")
	return cmd
}
